];

/**
 * Alias @emotion/server to @emotion/css to prevent LeafyGreen's emotion package
 * from pulling in SSR dependencies that use Node.js Buffer.
 * https://jira.mongodb.org/browse/EVG-17077
 * @internal
 */
export const viteFinal: StorybookConfig["viteFinal"] = (config) => {
  config.resolve = config.resolve ?? {};
  config.resolve.alias = {
    ...config.resolve.alias,
    "@emotion/server": "@emotion/css",
  };
  return config;
};

  const handleOnSubmit = () => {
    if (isValid) {
      onSubmit(input);
      if (clearOnSubmit) {
        setInput("");
      }
    }
  };

  const handleOnChange = (v: string) => {
    if (validator(v)) {
      onChange(v);
    }
    setInput(v);
  };

  return (
    <TextInputWithGlyph
      ref={ref}
      aria-label={ariaLabel ?? ""}
      disabled={disabled}
      icon={
        isValid ? (
          <IconButton
            aria-label="Select plus button"
            disabled={disabled}
            onClick={handleOnSubmit}
          >
            <Icon glyph="Plus" />
          </IconButton>
        ) : (
          <IconWithTooltip
            aria-label="validation error"
            fill={yellow.base}
            glyph="Warning"
          >
            {validatorErrorMessage}
          </IconWithTooltip>
        )
      }
      label={label}
      onChange={(e) => handleOnChange(e.target.value)}
      onKeyDown={(e: React.KeyboardEvent<HTMLInputElement>) =>
        e.key === "Enter" && handleOnSubmit()
      }
      value={input}
      {...rest}
    />
  );
});

TextInputWithValidation.displayName = "TextInputWithValidation";
export default TextInputWithValidation;

