const handleOnSubmit = () => {
    if (isValid) {
      onSubmit(input);
      if (clearOnSubmit) {
        setInput("");
      }
    }
  };

  const handleOnChange = (v: string) => {
    if (validator(v)) {
      onChange(v);
    }
    setInput(v);
  };

  return (
    <TextInputWithGlyph
      ref={ref}
      aria-label={ariaLabel ?? ""}
      disabled={disabled}
      icon={
        isValid ? (
          <IconButton
            aria-label="Select plus button"
            disabled={disabled}
            onClick={handleOnSubmit}
          >
            <Icon glyph="Plus" />
          </IconButton>
        ) : (
          <IconWithTooltip
